import express from 'express';
import path from 'path';

const app = express();

const publicDir = path.join(__dirname, '..', 'public');

app.use(express.static(publicDir));

app.get('/health', (_req, res) => {
  res.json({ status: 'ok' });
});

app.get('/', (_req, res) => {
  res.sendFile(path.join(publicDir, 'index.html'));
});

const PORT = Number(process.env.PORT) || 3000;

if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server listening on http://localhost:${PORT}`);
  });
}

export default app;

import assert from 'assert';
import path from 'path';
import { existsSync, readFileSync, rmSync, mkdirSync } from 'fs';
import { execFileSync } from 'child_process';

describe('Tailwind CSS build pipeline', function () {
  this.timeout(20000);

  const projectRoot = path.join(__dirname, '..');
  const input = path.join(projectRoot, 'src', 'styles', 'input.css');
  const outDir = path.join(projectRoot, 'public');
  const output = path.join(outDir, 'styles.css');

  it('builds styles.css with expected utilities', () => {
    if (!existsSync(outDir)) {
      mkdirSync(outDir, { recursive: true });
    }
    if (existsSync(output)) {
      rmSync(output);
    }

    const cli = require.resolve('tailwindcss/lib/cli.js');
    execFileSync('node', [cli, '-i', input, '-o', output], {
      stdio: 'inherit',
      cwd: projectRoot,
    });

    assert.ok(existsSync(output), 'styles.css should exist after build');
    const css = readFileSync(output, 'utf8');
    // index.html includes class="text-blue-500", so Tailwind should emit that utility
    assert.ok(css.includes('.text-blue-500'), 'styles.css should include .text-blue-500 utility');
  });
});
